class Solution {
public:
    bool equalFrequency(string word) {
        for (int i = 0; i < word.size(); i++) {
            string temp = word;
            temp.erase(i, 1);
            unordered_map<char, int> freq;
            for (char c : temp) {
                freq[c]++;
            }
            bool flag = true;
            int max = 0;
            int min = INT_MAX;
            for (auto& pair : freq) {
                if (pair.second > max) {
                    max = pair.second;
                }
                if (pair.second < min) {
                    min = pair.second;
                }
                if (pair.second != max && pair.second != min) {
                    flag = false;
                    break;
                }
            }
            if (flag) {
                return true;
            }
        }
        return false;
    }
};
